  def is_valid_heap(self, nums: list[int]) -> bool:
    if len(nums) == 0: return True
    for i in range(len(nums) // 2):
      if nums[i] < max(nums[i * 2 + 1:i * 2 + 2 + len(nums) // 2]):
        return False
    return True

def main():
  nums = [int(x) for x in input().split()]
  print(Solution().is_valid_heap(nums))

