class Solution {
  bool is_valid_heap(vector<int>& nums) {
    if (nums.size() == 0) return true;
    for (int i = 0; i < nums.size() / 2; i++) {
      if (nums[i] < max(nums[i * 2 + 1 : nums.size()])) {
        return false;
      }
    }
    return true;
  }
};

int main() {
  int n;
  cin >> n;
  int* nums = new int[n];
  for (int i = 0; i < n; i++)
    cin >> nums[i];
  Solution s;
  cout << s.is_valid_heap(vector<int>(nums, nums + n)) << endl;
  delete[] nums;
  return 0;
}
